// Each view has a change-detection mode that gates whether the pass descends into it.
// Conceptually (simplified from Angular's internals):
enum ChangeDetectionMode {
  CheckAlways, // Default strategy: always checked when the pass reaches it
  CheckOnce,   // Will be checked this pass, then flips to Checked (OnPush after markForCheck)
  Checked,     // OnPush and not dirty: the pass skips this subtree
  Detached     // detach() was called: the pass never descends here until reattach()
}

// The walker (pseudo-code):
function refreshView(view: View) {
  if (view.mode === ChangeDetectionMode.Checked ||
      view.mode === ChangeDetectionMode.Detached) {
    return; // skip this component AND its entire subtree
  }
  updateInputBindings(view);
  runDoCheckAndOnChanges(view);
  evaluateTemplateAndPatchDom(view);
  for (const child of view.children) {
    refreshView(child);
  }
  if (view.strategy === 'OnPush') {
    view.mode = ChangeDetectionMode.Checked; // clean until marked again
  }
}

import { Component, NgZone, inject } from '@angular/core';

@Component({ selector: 'app-ticker', template: '{{ frames }}' })
export class TickerComponent {
  frames = 0;
  private zone = inject(NgZone);

  // A 60fps loop that must NOT trigger a CD pass every frame.
  startExpensiveLoop() {
    // Run outside Angular's zone so requestAnimationFrame does not schedule tick().
    this.zone.runOutsideAngular(() => {
      const loop = () => {
        this.frames++;                 // mutate freely, no CD triggered
        if (this.frames % 30 === 0) {
          // Re-enter the zone only when we actually want the DOM updated.
          this.zone.run(() => {});     // schedules exactly one CD pass
        }
        requestAnimationFrame(loop);
      };
      requestAnimationFrame(loop);
    });
  }
}

import { ChangeDetectionStrategy, Component, Input, input } from '@angular/core';

@Component({
  selector: 'app-user-card',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <h3>{{ user().name }}</h3>
    <p>{{ user().email }}</p>
    <button (click)="expanded = !expanded">Toggle</button>
    @if (expanded) { <pre>{{ user() | json }}</pre> }
  `
})
export class UserCardComponent {
  // Signal input: reading user() in the template ties this view to the signal.
  user = input.required<{ name: string; email: string }>();
  expanded = false; // toggled via (click), which marks THIS OnPush view dirty
}

import { ChangeDetectionStrategy, ChangeDetectorRef, Component, NgZone, inject, OnInit, OnDestroy } from '@angular/core';

@Component({
  selector: 'app-live-price',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: '<span>{{ price }}</span>'
})
export class LivePriceComponent implements OnInit, OnDestroy {
  price = 0;
  private cdr = inject(ChangeDetectorRef);
  private zone = inject(NgZone);
  private socket?: WebSocket;

  ngOnInit() {
    this.socket = new WebSocket('wss://feed.example.com/prices');
    // A raw WebSocket message is NOT a template event, an input change,
    // an async pipe, or a signal write -> OnPush will NOT refresh on its own.
    this.socket.onmessage = (evt) => {
      this.price = JSON.parse(evt.data).price;
      this.cdr.markForCheck(); // schedule this view for the next pass
    };
  }

  ngOnDestroy() { this.socket?.close(); }
}

// PARENT passing a list to an OnPush child
@Component({
  selector: 'app-todo-page',
  template: '<app-todo-list [items]="todos"></app-todo-list>\n<button (click)="addBroken()">Add (broken)</button>'
})
export class TodoPageComponent {
  todos: string[] = ['buy milk'];

  // BUG: push mutates the SAME array reference. OnPush child never updates.
  addBroken() {
    this.todos.push('walk dog'); // todos === todos (same reference) -> no input change
  }
}

@Component({
  selector: 'app-todo-list',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: '@for (t of items; track t) { <li>{{ t }}</li> }'
})
export class TodoListComponent {
  @Input() items: string[] = [];
}

// FIX A: create a NEW reference so OnPush sees an input change.
addFixedImmutable() {
  this.todos = [...this.todos, 'walk dog']; // new array reference -> input change fires
}

// FIX B: model the list as a signal; writing it marks readers dirty.
import { signal } from '@angular/core';
todos = signal<string[]>(['buy milk']);
addFixedSignal() {
  this.todos.update(list => [...list, 'walk dog']); // signal write -> view marked dirty
}

// FIX C (last resort): keep mutating, but tell Angular explicitly.
// Requires injecting ChangeDetectorRef in the component that owns `todos`
// and does not help a child that received it by reference unless the child
// itself calls markForCheck. Prefer FIX A or B.

// main.ts - bootstrap zoneless (Angular 18: experimental; Angular 20+: stable)
import { bootstrapApplication } from '@angular/platform-browser';
import { provideZonelessChangeDetection } from '@angular/core';
import { AppComponent } from './app/app.component';

bootstrapApplication(AppComponent, {
  providers: [
    // Angular 18/19 experimental name:
    //   provideExperimentalZonelessChangeDetection()
    // Angular 20+ stable name:
    provideZonelessChangeDetection()
  ]
});

// Also delete the Zone.js import from polyfills (or the 'zone.js' entry in angular.json).
// Without Zone.js loaded, nothing else schedules CD; you MUST use signals,
// async pipe, or markForCheck for every dynamic value.

import { Pipe, PipeTransform } from '@angular/core';

// Pure pipe (default): recomputed ONLY when its input reference changes,
// not on every CD pass. This is why a pipe beats a method call in a template.
@Pipe({ name: 'currencyFmt' })
export class CurrencyFmtPipe implements PipeTransform {
  transform(value: number, code = 'USD'): string {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: code }).format(value);
  }
}
// In template: {{ row.total | currencyFmt }}  -- cached until row.total changes.

import {
  ChangeDetectionStrategy, ChangeDetectorRef, Component,
  NgZone, OnDestroy, OnInit, inject, signal
} from '@angular/core';

interface Quote { id: string; symbol: string; price: number; }

@Component({
  selector: 'app-trading-grid',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <table>
      <tbody>
        @for (q of quotes(); track q.id) {
          <tr>
            <td>{{ q.symbol }}</td>
            <td>{{ q.price | currencyFmt }}</td>
          </tr>
        }
      </tbody>
    </table>
  `
})
export class TradingGridComponent implements OnInit, OnDestroy {
  // Signal holds the row snapshot; we replace the array (new reference) on paint.
  quotes = signal<Quote[]>([]);

  private cdr = inject(ChangeDetectorRef);
  private zone = inject(NgZone);
  private socket?: WebSocket;
  private buffer = new Map<string, Quote>();
  private raf = 0;

  ngOnInit() {
    // Detach: high-frequency messages must NOT each trigger a CD pass.
    this.cdr.detach();

    this.zone.runOutsideAngular(() => {
      this.socket = new WebSocket('wss://feed.example.com/quotes');
      this.socket.onmessage = (evt) => {
        const q: Quote = JSON.parse(evt.data);
        this.buffer.set(q.id, q); // coalesce bursts in a buffer, no CD yet
      };

      // Repaint at most ~10 times per second regardless of message rate.
      const paint = () => {
        if (this.buffer.size) {
          // New array reference -> signal write -> view is dirty.
          this.quotes.set([...this.buffer.values()]);
          this.cdr.detectChanges(); // run CD for THIS subtree only, on our schedule
          this.buffer.clear();
        }
        this.raf = window.setTimeout(paint, 100);
      };
      paint();
    });
  }

  ngOnDestroy() {
    clearTimeout(this.raf);
    this.socket?.close();
  }
}

// TRIGGERS the error: a child's ngAfterViewInit mutates a value the parent
// already rendered this pass, or a parent reads a getter that changes each read.
@Component({
  selector: 'app-clock',
  template: '<span>{{ now }}</span>'
})
export class ClockComponent {
  // BUG: new value every read -> differs between the two dev passes.
  get now() { return Date.now(); }
}

// Another classic: setting a bound property in ngAfterViewInit.
ngAfterViewInit() {
  this.title = 'loaded'; // parent already checked title this pass -> error
}

// FIXES
// 1) Do not compute changing values in getters; snapshot them.
now = Date.now(); // set once (or update via interval + markForCheck), stable per pass

// 2) Defer the mutation to the NEXT tick so it belongs to a fresh pass.
import { ChangeDetectorRef, inject } from '@angular/core';
private cdr = inject(ChangeDetectorRef);
ngAfterViewInit() {
  Promise.resolve().then(() => {
    this.title = 'loaded';
    this.cdr.markForCheck();
  });
}

// 3) Best modern fix: use a signal; signal reads are stable within a pass
//    and the write schedules a clean subsequent pass.
title = signal('loading');
ngAfterViewInit() { this.title.set('loaded'); }

