import { ChangeDetectionStrategy, Component, Input, signal } from '@angular/core';

interface Filters { active: boolean; query: string; }

// FIX A: immutable update -> new object reference -> OnPush input change fires.
@Component({
  selector: 'app-filter-page',
  template: '<app-filter-summary [filters]="filters"></app-filter-summary>\n<button (click)="toggle()">Toggle</button>'
})
export class FilterPageComponent {
  filters: Filters = { active: false, query: '' };
  toggle() {
    // Was: this.filters.active = true;  (same reference -> child never updates)
    this.filters = { ...this.filters, active: !this.filters.active };
  }
}

// FIX B: signal-based. Writing the signal marks reader views dirty; works under zoneless too.
@Component({
  selector: 'app-filter-page-signal',
  template: '<app-filter-summary [filters]="filters()"></app-filter-summary>\n<button (click)="toggle()">Toggle</button>'
})
export class FilterPageSignalComponent {
  filters = signal<Filters>({ active: false, query: '' });
  toggle() {
    this.filters.update(f => ({ ...f, active: !f.active }));
  }
}

@Component({
  selector: 'app-filter-summary',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: '<span>Active: {{ filters.active }}</span>'
})
export class FilterSummaryComponent {
  @Input({ required: true }) filters!: Filters;
}

import { ChangeDetectionStrategy, Component, Pipe, PipeTransform, computed, signal } from '@angular/core';

interface Product { id: string; name: string; price: number; }
interface Row { id: string; name: string; slug: string; discounted: number; }

// Pure pipe replaces the impure slugify; recomputes only when input changes.
@Pipe({ name: 'slugify' })
export class SlugifyPipe implements PipeTransform {
  transform(v: string): string { return v.toLowerCase().replace(/\s+/g, '-'); }
}

@Component({
  selector: 'app-product-list',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <input (input)="onSearch($any($event.target).value)" placeholder="Search" />
    <ul>
      @for (r of rows(); track r.id) {
        <li>{{ r.name }} - {{ r.slug }} - {{ r.discounted }}</li>
      }
    </ul>
  `
})
export class ProductListComponent {
  private all = signal<Product[]>([]);
  private query = signal('');

  // Derived, memoized rows: recompute only when all or query changes.
  rows = computed<Row[]>(() => {
    const q = this.query().toLowerCase();
    return this.all()
      .filter(p => p.name.toLowerCase().includes(q))
      .map(p => ({
        id: p.id,
        name: p.name,
        slug: p.name.toLowerCase().replace(/\s+/g, '-'),
        discounted: Math.round(p.price * 0.9 * 100) / 100 // precomputed, no template method
      }));
  });

  setProducts(list: Product[]) { this.all.set(list); }
  onSearch(value: string) { this.query.set(value); }
}

