import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

@Component({
  selector: 'app-notification-banner',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: '@if (message()) { <div class="banner">{{ message() }}</div> }'
})
export class NotificationBannerComponent {
  // FIX: signal instead of a plain field. Writing it schedules a pass
  // under zoneless with no Zone.js required.
  message = signal<string>('');

  show(text: string) {
    // Even inside a raw setTimeout, setting the signal notifies Angular.
    setTimeout(() => this.message.set(text), 0);
  }
}

